var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"예? 델타 세븐이라면…….","JPN":"はい？　デルタセブンなら……","ENG":"Pardon? Delta Seven is...","TWN":"嗯？第七三角洲部隊……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"그래, 전략특수전 사령부 델타 세븐. 대침식전에서 뛰어난 성과를 보이고 있는 부대지.","JPN":"そうだ、戦略特殊戦司令部デルタセブン。対侵食戦で目覚ましい成果をあげている部隊だ。","ENG":"Yes. Delta Seven of the Strategic Special Operations Command. They showed outstanding results in anti-Corruption warfare.","TWN":"沒錯，戰略特戰司令部的第七三角洲部隊，是在侵蝕體對抗戰中取得卓越成績的部隊。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"세계 각지에 출몰하는 정체불명의 고치에 대한 대비를 위해 새로 인원을 충원한다더군.","JPN":"世界各地に出没する正体不明の繭に対処するために、新しく人員を募集しているそうだ。","ENG":"They are looking for new recruits to prepare for the unidentified cocoons that have been appearing all throughout the world.","TWN":"為了應付出現在世界各地來歷不明的繭，他們打算增加新隊員。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"그래서 우리 카운터 양성 프로젝트에서 가장 우수한 성적을 거둔 너를 실전배치의 일환으로 델타 세븐에 편입시키기로 했다.","JPN":"そこで、我々カウンター養成プロジェクトで最も優秀な成績を収めた君を、実戦配置の一環としてデルタセブンに編入させることにした。","ENG":"So, we decided to assign you to Delta Seven, as you scored the highest on our Counter training project.","TWN":"所以，我們決定將制裁者培育計畫中取得優異成績的你，作為實戰部署中的一環編入第七三角洲部隊。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"넌 이제부터 델타 세븐 내사과 소속의 카린 웡 대위가 되는 거야.","JPN":"君はこれからデルタセブン内偵課所属のカリン・ウォン大尉になるんだ。","ENG":"From now on, you'll be Captain Karin Wong of the Internal Investigation Department of Delta Seven.","TWN":"從現在起，你就是第七三角洲部隊內務科的一員了，卡琳大尉。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그게 정말인가요?","JPN":"それは本当ですか？","ENG":"Could this really be true?","TWN":"真的嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제가 델타 세븐 소속……","JPN":"私がデルタセブン所属……","ENG":"Me? Delta Seven?","TWN":"要我加入第七三角洲部隊……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"결재에 착오가 있을지도 몰라요.","JPN":"決裁に間違いがあったのかもしれません。","ENG":"There may have been an error with the paperwork.","TWN":"說不定這個決策是錯誤的。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"진위 여부에 대한 사실 확인 절차를 위해 국방부 직인이 찍힌 명령서를 보여주시겠어요?","JPN":"真偽の程について事実確認の手続きのため、国防部の捺印のある命令書を見せていただけますか？","ENG":"Just to be safe, I think this may warrant a verification of the respective documentation by the parties affected.","TWN":"以防萬一，請提出有國防部用印的公文以確認真偽。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"자, 여기 실컷 읽어봐라.","JPN":"ほら、これだ。好きなだけ読んでみろ。","ENG":"Here you go. Read it all you'd like.","TWN":"來，就在這裡，自己好好看看吧。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"뭐, 요즘 같은 뒤숭숭한 시대에 델타 세븐에 불려 간다는 것 자체가 그리 좋은 일은 아닌 것 같다만……","JPN":"この物騒なご時世じゃ、デルタセブンに異動になったこと自体があまり良くないことだろうが……","ENG":"Then again, I guess getting dragged to Delta Seven's not exactly something to celebrate...","TWN":"不過，在這個混亂的世代，光是被第七三角洲部隊叫過去就肯定不是什麼好事……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"어쨌든 훈련병 주제에 대위 진급이라는 전례 없는 특혜다.","JPN":"まぁ、訓練兵から大尉への進級は、前例のない特別な措置だ。","ENG":"Anyway, you're going from a trainee straight to captain. I've never seen anyone get this kind of special treatment.","TWN":"對，一個訓練兵居然直接晉升為大尉，這可是特別待遇。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"괜한 트집 잡히기 싫으면 우쭐해하지 말고 처신 잘해야 할 거야.","JPN":"変な言いがかりをつけられなくなかったら、調子に乗らずに立ち振る舞いに気をつけろ。","ENG":"So you'd better carry yourself well. Don't get cocky, or others might look for a way to bring you down.","TWN":"如果你不想被抓到把柄就低調一點。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니요. 저는 이 프로젝트에 자원한 순간부터, 군인의 사명을 다하기로 결심했어요.","JPN":"いいえ。私はこのプロジェクトに志願した時点で、軍人としての使命を果たすと心に決めています。","ENG":"No. I decided to fulfill my duties as a soldier the second I volunteered for this project.","TWN":"不，打從我加入這個計劃開始，我就決定要善盡軍人的使命。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"현장에서 시민들을 위해 싸우는 건 오히려 제가 원하던 바예요.","JPN":"現場で市民のために戦えるのは、むしろ願ってもないことです。","ENG":"Fighting for the citizens on the field is what I wanted.","TWN":"我反而希望能在現場為市民們拋頭顱灑熱血。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그리고 교관 중위? 여긴 군대예요. 상관인 제게 하대는 지양해주셨으면 좋겠군요.","JPN":"それに教官中尉？　ここは軍です。上官である私をぞんざいに扱うことはご遠慮願います。","ENG":"And Instructor Lieutenant? This is the military. I advise you to refrain from treating your superior like a subordinate.","TWN":"教官中尉？這裡是軍隊，長官對下屬的命令是絕對的。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"야! 너 아직 진급식도 안 했거든!","JPN":"おい、こら。まだ進級申告式もやってないぞ。","ENG":"Hey, you little brat. You haven't even had your promotion ceremony yet, all right?","TWN":"喂！你又還沒參加晉升儀式！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};